import { describe, expect, it } from "vitest";
import { LruCache } from "../src/lruCache";

describe("LruCache", () => {
  it("evicts the least recently used entry", () => {
    const cache = new LruCache<string, number>({ maxSize: 2 });
    cache.set("a", 1);
    cache.set("b", 2);
    expect(cache.get("a")).toBe(1);
    cache.set("c", 3);
    expect(cache.get("b")).toBeUndefined();
    expect(cache.get("a")).toBe(1);
    expect(cache.stats.evictions).toBe(1);
  });

  it("expires entries and counts expired misses", () => {
    let now = 1000;
    const cache = new LruCache<string, string>({ maxSize: 2, ttlMs: 50, now: () => now });
    cache.set("token", "abc");
    now = 1051;
    expect(cache.get("token")).toBeUndefined();
    expect(cache.stats.expired).toBe(1);
    expect(cache.stats.misses).toBe(1);
  });

  it("updates values and clears entries without resetting stats", () => {
    const cache = new LruCache<string, number>({ maxSize: 1 });
    cache.set("a", 1);
    cache.set("a", 2);
    expect(cache.get("a")).toBe(2);
    cache.clear();
    expect(cache.size).toBe(0);
    expect(cache.stats.hits).toBe(1);
  });
});

export type CacheStats = {
  hits: number;
  misses: number;
  evictions: number;
  expired: number;
};

type Entry<Value> = {
  value: Value;
  expiresAt: number | null;
};

export type LruCacheOptions = {
  maxSize: number;
  ttlMs?: number;
  now?: () => number;
};

export class LruCache<Key, Value> {
  readonly #maxSize: number;
  readonly #ttlMs: number | null;
  readonly #now: () => number;
  readonly #entries = new Map<Key, Entry<Value>>();
  readonly #stats: CacheStats = {
    hits: 0,
    misses: 0,
    evictions: 0,
    expired: 0,
  };

  constructor(options: LruCacheOptions) {
    if (!Number.isInteger(options.maxSize) || options.maxSize < 1) {
      throw new Error("maxSize must be a positive integer");
    }
    if (options.ttlMs !== undefined && (!Number.isFinite(options.ttlMs) || options.ttlMs <= 0)) {
      throw new Error("ttlMs must be a positive number");
    }
    this.#maxSize = options.maxSize;
    this.#ttlMs = options.ttlMs ?? null;
    this.#now = options.now ?? Date.now;
  }

  get size(): number {
    this.#pruneExpired();
    return this.#entries.size;
  }

  get stats(): CacheStats {
    return { ...this.#stats };
  }

  get(key: Key): Value | undefined {
    const entry = this.#entries.get(key);
    if (!entry) {
      this.#stats.misses += 1;
      return undefined;
    }
    if (this.#isExpired(entry)) {
      this.#entries.delete(key);
      this.#stats.expired += 1;
      this.#stats.misses += 1;
      return undefined;
    }
    this.#entries.delete(key);
    this.#entries.set(key, entry);
    this.#stats.hits += 1;
    return entry.value;
  }

  has(key: Key): boolean {
    const entry = this.#entries.get(key);
    if (!entry) return false;
    if (this.#isExpired(entry)) {
      this.#entries.delete(key);
      this.#stats.expired += 1;
      return false;
    }
    return true;
  }

  set(key: Key, value: Value, ttlMs = this.#ttlMs): void {
    if (ttlMs !== null && (!Number.isFinite(ttlMs) || ttlMs <= 0)) {
      throw new Error("ttlMs must be a positive number");
    }
    if (this.#entries.has(key)) this.#entries.delete(key);
    this.#entries.set(key, {
      value,
      expiresAt: ttlMs === null ? null : this.#now() + ttlMs,
    });
    this.#evictOverflow();
  }

  delete(key: Key): boolean {
    return this.#entries.delete(key);
  }

  clear(): void {
    this.#entries.clear();
  }

  #evictOverflow(): void {
    while (this.#entries.size > this.#maxSize) {
      const oldestKey = this.#entries.keys().next().value as Key | undefined;
      if (oldestKey === undefined) return;
      this.#entries.delete(oldestKey);
      this.#stats.evictions += 1;
    }
  }

  #pruneExpired(): void {
    for (const [key, entry] of this.#entries) {
      if (this.#isExpired(entry)) {
        this.#entries.delete(key);
        this.#stats.expired += 1;
      }
    }
  }

  #isExpired(entry: Entry<Value>): boolean {
    return entry.expiresAt !== null && entry.expiresAt <= this.#now();
  }
}

